diff --git a/cmd/entire/cli/strategy/manual_commit_hooks.go b/cmd/entire/cli/strategy/manual_commit_hooks.go
index 17129ec..774de8c 100644
--- a/cmd/entire/cli/strategy/manual_commit_hooks.go
+++ b/cmd/entire/cli/strategy/manual_commit_hooks.go
@@ -1041,6 +1041,10 @@ func (s *ManualCommitStrategy) condenseAndUpdateState(
 	state.PendingPromptAttribution = nil
 	state.FilesTouched = nil

+	// Clear filesystem prompt.txt so subsequent checkpoints don't carry over
+	// prompts from the condensed checkpoint. The next TurnStart will append fresh.
+	clearFilesystemPrompt(ctx, state.SessionID)
+
 	// Save checkpoint ID so subsequent commits can reuse it (e.g., amend restores trailer)
 	state.LastCheckpointID = checkpointID

